"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[4213],{74788(n,t,r){r.r(t),r.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>c,frontMatter:()=>i,metadata:()=>o,toc:()=>p});const o=JSON.parse('{"id":"cpp17/optional","title":"std::optional (\u53ef\u9009\u503c)","description":"C++17 std::optional (\u53ef\u9009\u503c) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/40-optional.md","sourceDirName":"cpp17","slug":"/cpp17/40-optional","permalink":"/LearnModernCpp/docs/cpp17/40-optional","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"optional","permalink":"/LearnModernCpp/docs/tags/optional"}],"version":"current","sidebarPosition":41,"frontMatter":{"sidebar_position":41,"slug":"40-optional","title":"std::optional (\u53ef\u9009\u503c)","description":"C++17 std::optional (\u53ef\u9009\u503c) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","optional"]},"sidebar":"docs","previous":{"title":"__has_include \u9884\u5904\u7406\u68c0\u67e5","permalink":"/LearnModernCpp/docs/cpp17/08-has-include"},"next":{"title":"std::variant \u4e0e std::visit (\u7c7b\u578b\u5b89\u5168\u8054\u5408\u4f53)","permalink":"/LearnModernCpp/docs/cpp17/41-variant"}}');var e=r(74848),s=r(28453);const i={sidebar_position:41,slug:"40-optional",title:"std::optional (\u53ef\u9009\u503c)",description:"C++17 std::optional (\u53ef\u9009\u503c) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","optional"]},a="std::optional (\u53ef\u9009\u503c)",l={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function d(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,e.jsxs)(e.Fragment,{children:[(0,e.jsx)(t.header,{children:(0,e.jsx)(t.h1,{id:"stdoptional-\u53ef\u9009\u503c",children:"std::optional (\u53ef\u9009\u503c)"})}),"\n",(0,e.jsx)(t.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 std::optional (\u53ef\u9009\u503c) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,e.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,e.jsx)(t.pre,{children:(0,e.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp17/40_optional.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::optional (\u53ef\u9009\u503c)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u4e00\u4e2a\u53ef\u4ee5\u300c\u6709\u503c\u300d\u6216\u300c\u65e0\u503c\u300d\u7684\u5305\u88c5\u7c7b\u578b\u3002\u8868\u793a\u4e00\u4e2a\u503c\u53ef\u80fd\u5b58\u5728\r\n *          \u4e5f\u53ef\u80fd\u4e0d\u5b58\u5728\uff0c\u7c7b\u4f3c\u5176\u4ed6\u8bed\u8a00\u4e2d\u7684 Option/Maybe \u7c7b\u578b\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++14 \u4e2d\u8868\u793a\u300c\u53ef\u80fd\u65e0\u503c\u300d\u901a\u5e38\u7528\u6307\u9488(nullptr)\u3001\r\n *              \u54e8\u5175\u503c(-1, "")\u6216 pair<bool,T>\uff0c\u90fd\u4e0d\u591f\u7c7b\u578b\u5b89\u5168\r\n *              \u4e14\u8bed\u4e49\u4e0d\u660e\u786e\u3002optional \u63d0\u4f9b\u4e86\u7edf\u4e00\u3001\u5b89\u5168\u7684\u89e3\u51b3\u65b9\u6848\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - std::optional<T> \u8981\u4e48\u6301\u6709\u4e00\u4e2a T \u503c\uff0c\u8981\u4e48\u662f std::nullopt\r\n *   - .value() \u5728\u65e0\u503c\u65f6\u629b\u51fa std::bad_optional_access \u5f02\u5e38\r\n *   - .value_or(default) \u65e0\u503c\u65f6\u8fd4\u56de\u9ed8\u8ba4\u503c\uff0c\u4e0d\u629b\u5f02\u5e38\r\n *   - \u53ef\u4ee5\u7528 if (opt) \u6216 if (opt.has_value()) \u68c0\u67e5\u662f\u5426\u6709\u503c\r\n *   - \u4e0d\u4f1a\u6709\u5806\u5206\u914d\u2014\u2014\u503c\u76f4\u63a5\u5b58\u50a8\u5728 optional \u5bf9\u8c61\u5185\u90e8\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <optional>\r\n#include <string>\r\n#include <vector>\r\n#include <map>\r\n#include <cmath>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// \u51fd\u6570\u8fd4\u56de optional \u2014\u2014 \u66ff\u4ee3\u8fd4\u56de\u6307\u9488\u6216\u54e8\u5175\u503c\r\nstd::optional<int> find_first_even(const std::vector<int>& vec) {\r\n    for (int v : vec) {\r\n        if (v % 2 == 0) return v;  // \u9690\u5f0f\u6784\u9020 optional\r\n    }\r\n    return std::nullopt;  // \u8868\u793a\u672a\u627e\u5230\r\n}\r\n\r\n// \u53e6\u4e00\u4e2a\u4f8b\u5b50\uff1a\u5b89\u5168\u7684\u9664\u6cd5\r\nstd::optional<double> safe_divide(double a, double b) {\r\n    if (b == 0.0) return std::nullopt;\r\n    return a / b;\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // 1. \u521b\u5efa optional\r\n    std::optional<int> opt1;                  // \u7a7a\uff0cnullopt\r\n    std::optional<int> opt2 = 42;             // \u6709\u503c\r\n    std::optional<int> opt3 = std::nullopt;   // \u663e\u5f0f\u7a7a\r\n    std::optional<std::string> opt4{"hello"}; // \u6709\u503c\r\n\r\n    // 2. \u68c0\u67e5\u662f\u5426\u6709\u503c\r\n    std::cout << "opt1 \u6709\u503c: " << opt1.has_value() << "\\n";\r\n    std::cout << "opt2 \u6709\u503c: " << opt2.has_value() << "\\n";\r\n    std::cout << "opt3 \u6709\u503c: " << (opt3 ? "\u662f" : "\u5426") << "\\n";  // bool \u8f6c\u6362\r\n\r\n    // 3. \u8bbf\u95ee\u503c\r\n    std::cout << "opt2.value() = " << opt2.value() << "\\n";\r\n    std::cout << "*opt2        = " << *opt2 << "\\n";  // \u89e3\u5f15\u7528\r\n\r\n    // 4. value_or \u2014\u2014 \u63d0\u4f9b\u9ed8\u8ba4\u503c\r\n    std::cout << "opt1.value_or(0) = " << opt1.value_or(0) << "\\n";\r\n    std::cout << "opt2.value_or(0) = " << opt2.value_or(0) << "\\n";\r\n\r\n    // 5. \u51fd\u6570\u8fd4\u56de optional\r\n    std::vector<int> nums{1, 3, 5, 8, 9};\r\n    if (auto result = find_first_even(nums)) {\r\n        std::cout << "\u7b2c\u4e00\u4e2a\u5076\u6570: " << *result << "\\n";\r\n    } else {\r\n        std::cout << "\u6ca1\u6709\u5076\u6570\\n";\r\n    }\r\n\r\n    std::vector<int> odds{1, 3, 5, 7};\r\n    auto result2 = find_first_even(odds);\r\n    std::cout << "\u5168\u662f\u5947\u6570\u65f6: " << result2.value_or(-1) << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. optional \u505a\u7c7b\u6210\u5458 \u2014\u2014 \u8868\u793a\u53ef\u9009\u5b57\u6bb5\r\nstruct UserProfile {\r\n    std::string name;\r\n    std::optional<std::string> email;       // \u53ef\u9009\r\n    std::optional<int> age;                  // \u53ef\u9009\r\n    std::optional<std::string> nickname;     // \u53ef\u9009\r\n\r\n    void print() const {\r\n        std::cout << "  \u59d3\u540d: " << name << "\\n";\r\n        std::cout << "  \u90ae\u7bb1: " << email.value_or("\u672a\u8bbe\u7f6e") << "\\n";\r\n        std::cout << "  \u5e74\u9f84: ";\r\n        if (age) std::cout << *age << "\\n";\r\n        else     std::cout << "\u672a\u8bbe\u7f6e\\n";\r\n        std::cout << "  \u6635\u79f0: " << nickname.value_or(name) << "\\n";\r\n    }\r\n};\r\n\r\n// 2. optional \u94fe\u5f0f\u64cd\u4f5c\uff08\u6a21\u62df monadic \u64cd\u4f5c\uff0cC++23 \u624d\u6709 and_then\uff09\r\nstd::optional<std::string> get_config_value(const std::string& key) {\r\n    std::map<std::string, std::string> config{\r\n        {"host", "localhost"}, {"port", "8080"}\r\n    };\r\n    if (auto it = config.find(key); it != config.end()) {\r\n        return it->second;\r\n    }\r\n    return std::nullopt;\r\n}\r\n\r\nstd::optional<int> parse_int(const std::string& s) {\r\n    try {\r\n        return std::stoi(s);\r\n    } catch (...) {\r\n        return std::nullopt;\r\n    }\r\n}\r\n\r\n// 3. emplace \u2014\u2014 \u5c31\u5730\u6784\u9020\r\n// 4. \u4e0e\u6307\u9488\u65b9\u6848\u7684\u5bf9\u6bd4\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // \u53ef\u9009\u5b57\u6bb5\u7684\u7ed3\u6784\u4f53\r\n    UserProfile user1{"\u5f20\u4e09", "zhangsan@email.com", 25, std::nullopt};\r\n    UserProfile user2{"\u674e\u56db", std::nullopt, std::nullopt, "\u5c0f\u56db"};\r\n\r\n    std::cout << "\u7528\u62371:\\n";\r\n    user1.print();\r\n    std::cout << "\u7528\u62372:\\n";\r\n    user2.print();\r\n\r\n    // \u94fe\u5f0f\u67e5\u8be2\r\n    auto port_str = get_config_value("port");\r\n    std::optional<int> port;\r\n    if (port_str) {\r\n        port = parse_int(*port_str);\r\n    }\r\n    std::cout << "\u7aef\u53e3: " << port.value_or(80) << "\\n";\r\n\r\n    auto missing = get_config_value("timeout");\r\n    std::cout << "\u8d85\u65f6: " << missing.value_or("5000") << "\\n";\r\n\r\n    // emplace \u2014\u2014 \u5c31\u5730\u6784\u9020\uff0c\u907f\u514d\u4e34\u65f6\u5bf9\u8c61\r\n    std::optional<std::string> opt;\r\n    opt.emplace(5, \'A\');  // \u6784\u9020 string("AAAAA")\r\n    std::cout << "emplace \u6784\u9020: " << *opt << "\\n";\r\n\r\n    // reset \u2014\u2014 \u6e05\u9664\u503c\r\n    opt.reset();\r\n    std::cout << "reset \u540e\u6709\u503c: " << opt.has_value() << "\\n";\r\n\r\n    // optional \u6bd4\u8f83\r\n    std::optional<int> a = 5;\r\n    std::optional<int> b = 10;\r\n    std::optional<int> c;\r\n    std::cout << "5 < 10: " << (a < b) << "\\n";\r\n    std::cout << "nullopt < 5: " << (c < a) << "\\n";  // nullopt \u5c0f\u4e8e\u4efb\u4f55\u503c\r\n}\r\n\r\n// ============================================================\r\n// \u4e0e\u65e7\u65b9\u6848\u7684\u5bf9\u6bd4\r\n// ============================================================\r\nvoid compare_with_old() {\r\n    std::cout << "\\n--- \u4e0e\u65e7\u65b9\u6848\u5bf9\u6bd4 ---\\n";\r\n\r\n    // \u65b9\u6848 1: \u6307\u9488\u65b9\u6848 \u2014\u2014 \u9700\u8981\u52a8\u6001\u5206\u914d\u6216\u5f15\u7528\u5916\u90e8\u53d8\u91cf\r\n    // int* find_value_old(...) { return nullptr; }\r\n    // \u95ee\u9898\uff1a\u6240\u6709\u6743\u4e0d\u660e\u786e\uff0c\u53ef\u80fd\u60ac\u5782\r\n\r\n    // \u65b9\u6848 2: \u54e8\u5175\u503c \u2014\u2014 -1 \u8868\u793a\u672a\u627e\u5230\r\n    // int find_value_old(...) { return -1; }\r\n    // \u95ee\u9898\uff1a-1 \u53ef\u80fd\u662f\u5408\u6cd5\u503c\r\n\r\n    // \u65b9\u6848 3: pair<bool, T>\r\n    // pair<bool, int> find_value_old(...) { return {false, 0}; }\r\n    // \u95ee\u9898\uff1afalse \u65f6 second \u7684\u503c\u65e0\u610f\u4e49\u4f46\u4ecd\u9700\u6784\u9020\r\n\r\n    // \u65b9\u6848 4: optional \u2014\u2014 \u6700\u4f73\u65b9\u6848\r\n    auto result = safe_divide(10.0, 3.0);\r\n    std::cout << "10/3 = " << result.value_or(0.0) << "\\n";\r\n\r\n    auto bad = safe_divide(10.0, 0.0);\r\n    std::cout << "10/0 = " << (bad ? std::to_string(*bad) : "\u9664\u96f6\u9519\u8bef") << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: \u5bf9\u7a7a optional \u8c03\u7528 value() \u4f1a\u629b\u5f02\u5e38\r\n    std::optional<int> empty;\r\n    try {\r\n        auto v = empty.value();  // \u629b\u51fa bad_optional_access\r\n        (void)v;\r\n    } catch (const std::bad_optional_access& e) {\r\n        std::cout << "\u9677\u96311 - \u7a7a optional \u8c03\u7528 value(): " << e.what() << "\\n";\r\n    }\r\n\r\n    // \u9677\u9631 2: \u5bf9\u7a7a optional \u89e3\u5f15\u7528\u662f UB\uff08\u672a\u5b9a\u4e49\u884c\u4e3a\uff09\r\n    // auto v = *empty;  // UB\uff01\u4e0d\u4f1a\u629b\u5f02\u5e38\uff0c\u4f46\u884c\u4e3a\u672a\u5b9a\u4e49\r\n    std::cout << "\u9677\u96312 - \u5bf9\u7a7a optional \u7528 * \u89e3\u5f15\u7528\u662f UB\uff0c\u4e0d\u4f1a\u629b\u5f02\u5e38\\n";\r\n\r\n    // \u9677\u9631 3: optional<bool> \u7684\u6761\u4ef6\u5224\u65ad\u5bb9\u6613\u6df7\u6dc6\r\n    std::optional<bool> opt_false = false;\r\n    if (opt_false) {\r\n        // \u8fd9\u91cc\u4f1a\u8fdb\u5165\uff01\u56e0\u4e3a optional \u6709\u503c\uff08\u867d\u7136\u503c\u662f false\uff09\r\n        std::cout << "\u9677\u96313 - optional<bool>(false) \u8f6c bool \u4e3a true"\r\n                  << " (\u56e0\u4e3a\u6709\u503c)\uff0c\u503c=" << *opt_false << "\\n";\r\n    }\r\n\r\n    // \u9677\u9631 4: optional \u4e0d\u652f\u6301\u5f15\u7528\r\n    // std::optional<int&> ref_opt;  // \u7f16\u8bd1\u9519\u8bef\uff01\r\n    // \u66ff\u4ee3\u65b9\u6848\uff1a\u4f7f\u7528 std::reference_wrapper\r\n    std::cout << "\u9677\u96314 - optional \u4e0d\u652f\u6301\u5f15\u7528\u7c7b\u578b optional<T&>\\n";\r\n\r\n    // \u9677\u9631 5: optional \u6709\u989d\u5916\u5b58\u50a8\u5f00\u9500\r\n    std::cout << "\u9677\u96315 - sizeof(int)=" << sizeof(int)\r\n              << ", sizeof(optional<int>)=" << sizeof(std::optional<int>)\r\n              << " (\u591a\u4e86 bool \u6807\u5fd7 + \u5bf9\u9f50\u586b\u5145)\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::optional (\u53ef\u9009\u503c) - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    compare_with_old();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,e.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,e.jsxs)(t.ul,{children:["\n",(0,e.jsx)(t.li,{children:(0,e.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/utility/optional",children:"cppreference: std::optional (\u53ef\u9009\u503c)"})}),"\n"]})]})}function c(n={}){const{wrapper:t}={...(0,s.R)(),...n.components};return t?(0,e.jsx)(t,{...n,children:(0,e.jsx)(d,{...n})}):d(n)}},28453(n,t,r){r.d(t,{R:()=>i,x:()=>a});var o=r(96540);const e={},s=o.createContext(e);function i(n){const t=o.useContext(s);return o.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function a(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(e):n.components||e:i(n.components),o.createElement(s.Provider,{value:t},n.children)}}}]);